                "hostname"
            ]
        }
    },
    "mappings": {
        "dynamic": "strict",
        "properties": {
            "hostname": {
                "type": "keyword",
                "time_series_dimension": "true"
            },
            "cumulative_usage_user": {
                "type": "scaled_float",
